// Time:  O(n!)
// Space: O(n)

class Solution {
public:
    bool canVisitAllRooms(vector<vector<int>>& rooms) {
        unordered_set<int> lookup = {0};
        vector<int> stack = {0};
        while (!stack.empty()) {
            auto node = stack.back(); stack.pop_back();
            for (const auto& nei : rooms[node]) {
                if (!lookup.count(nei)) {
                    lookup.emplace(nei);
                    if (lookup.size() == rooms.size()) {
                        return true;
                    }
                    stack.emplace_back(nei);
                }
            }
        }
        return lookup.size() == rooms.size();
    }
};

# Time:  O(n!)
# Space: O(n)

class Solution(object):
    def canVisitAllRooms(self, rooms):
        """
        :type rooms: List[List[int]]
        :rtype: bool
        """
        lookup = set([0])
        stack = [0]
        while stack:
            node = stack.pop()
            for nei in rooms[node]:
                if nei not in lookup:
                    lookup.add(nei)
                    if len(lookup) == len(rooms):
                        return True
                    stack.append(nei)
        return len(lookup) == len(rooms)
